test_cases.assertion_pseudocode:
for each path in ["/healthz", "/readyz", "/version", "/auth/providers", "/auth/callback"]:
  resp = httptest_send(GET, path, headers={})
  assert resp.status != 401

approved_messages = {"missing authorization header", "invalid authorization header format", "missing token", "unrecognized token format", "invalid credentials", "credential revoked", "credential expired", "user is blocked", "forbidden", "insufficient permissions", "internal server error"}
for each error_triggering_request in all_error_scenarios:
  resp = run_middleware(error_triggering_request)
  msg = parse_json(resp.body).error.message
  assert msg in approved_messages

property_tests.invariant_check:
for credType in ["admin_token", "api_key"]:
  for permissions in [nil, [], ["some:perm"], ["keys:read"]]:
    ctx = new_echo_context_with_auth(AuthInfo{CredentialType:credType, Permissions:permissions})
    err = RequirePermission(ctx, random_resource_type, random_action)
    assert err == nil

edge_case_tests.assertion_pseudocode:
// Structural check: contextKey type is unexported
assert type_of(authInfoKey) == "auth.contextKey"  // unexported type

// Behavioral check: plain string key cannot retrieve AuthInfo
ctx = new_echo_context_with_auth_injected_by_middleware()
val = ctx.Get("auth_info")  // using plain string
assert val == nil  // AuthInfo is stored under unexported key type

// Code inspection:
source = read_file("internal/auth/credentials.go")
assert count_occurrences(source, "subtle.ConstantTimeCompare([]byte(") >= 1 OR
       count_occurrences(source, "subtle.ConstantTimeCompare") >= 1 AND
       // both args are []byte conversions, not raw string ==
assert no_occurrence_of(source, "hashToken(...) ==")
